mapper.select:
${pagingTop} SELECT * FROM ( SELECT survey_idx, survey_title, survey_content, survey_start_date, survey_end_date, survey_start_time, survey_end_time, CASE WHEN SURVEY_OPEN_YN = 'N' THEN 'N' WHEN SYSDATE BETWEEN TO_DATE(survey_start_date, 'YYYY-MM-DD') AND TO_DATE(survey_end_date, 'YYYY-MM-DD')+1 THEN 'Y' WHEN SYSDATE <= TO_DATE(survey_start_date, 'YYYY-MM-DD') THEN 'Y' ELSE 'N' END survey_open_yn, survey_private_yn, annyms_yn, limit_user_yn, limit_user_id, add_date, add_user_id, (SELECT COUNT(*) FROM CMS_SURVEY_ANSWER_USER b WHERE a.survey_idx = b.survey_idx and a.homepage_id = b.homepage_id) AS answer_count, add_user_tel, skin_cd, open_yn, name_yn, greetings, popup_yn, select_cnt FROM CMS_SURVEY_BASIC a
homepage_id = #{homepage_id}
AND ${search_type} like '%' || #{search_text} || '%'
ORDER BY survey_idx DESC ) ${pagingBottom}

${pagingTop} SELECT * FROM ( SELECT survey_idx, survey_title, survey_content, survey_start_date, survey_end_date, survey_start_time, survey_end_time, CASE WHEN SURVEY_OPEN_YN = 'N' THEN 'N' WHEN SYSDATE BETWEEN TO_DATE(survey_start_date, 'YYYY-MM-DD') AND TO_DATE(survey_end_date, 'YYYY-MM-DD')+1 THEN 'Y' ELSE 'N' END survey_open_yn, survey_private_yn, annyms_yn, limit_user_yn, limit_user_id, add_date, add_user_id, (SELECT COUNT(*) FROM CMS_SURVEY_ANSWER_USER b WHERE a.survey_idx = b.survey_idx and a.homepage_id = b.homepage_id) AS answer_count, add_user_tel, skin_cd, open_yn, name_yn, greetings, popup_yn, select_cnt FROM CMS_SURVEY_BASIC a
homepage_id = #{homepage_id} AND survey_private_yn = 'Y'
AND ${search_type} like '%' || #{search_text} || '%'
) ORDER BY survey_idx DESC ${pagingBottom}

SELECT homepage_id, survey_idx, survey_title, survey_content, survey_start_date, survey_end_date, survey_start_time, survey_end_time,
survey_open_yn, survey_private_yn, annyms_yn, limit_user_yn, limit_user_id, add_date, add_user_id, (SELECT COUNT(*) FROM CMS_SURVEY_ANSWER_USER b WHERE a.survey_idx = b.survey_idx and a.homepage_id = b.homepage_id) AS answer_count,
add_user_id AS add_user_name, a.add_user_tel, skin_cd, open_yn, name_yn, greetings, popup_yn, select_cnt FROM CMS_SURVEY_BASIC a WHERE homepage_id = #{homepage_id} AND survey_idx = #{survey_idx}

mapper.update:
