UPDATE CMS_SURVEY_BASIC
SET
	survey_open_yn = #{survey_open_yn}
WHERE
	homepage_id = #{homepage_id}
AND survey_idx = #{survey_idx}

UPDATE CMS_SURVEY_BASIC
