	homepage_id = #{homepage_id}
AND survey_idx = #{survey_idx}

UPDATE CMS_SURVEY_BASIC SET
	select_cnt = select_cnt + 1
WHERE
	homepage_id = #{homepage_id}
AND survey_idx = #{survey_idx}
